1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Step = QuoteStep;
7	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	};
14	
15	export const runScenario = (scenario: Scenario): unknown => {
16	  const results = scenario.steps.map((step) => {
17	    const basePremium = step.items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
18	    const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
19	    return { premium: basePremium + firstInsuranceSurcharge + PROCESSING_FEE };
20	  });
21	  return { results };
22	};
